// Aggregate all rows from Postgres into a single Telegram message.
// Returns [] if no qualifying jobs found — flow stops silently.

const rows = $input.all().map(item => item.json);

// Filter out the Postgres 'no rows' edge case (single row with null job_title)
const jobs = rows.filter(r => r.job_title);

if (jobs.length === 0) {
  return []; // Nothing to send — stop
}

function esc(text) {
  return (text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const medals = ['\u{1F947}', '\u{1F948}', '\u{1F949}', '4\uFE0F\u20E3', '5\uFE0F\u20E3'];

const today = new Date().toLocaleDateString('de-DE', {
  timeZone: 'Europe/Berlin',
  day: '2-digit', month: '2-digit', year: 'numeric'
});

const lines = [
  '\u{1F4CA} <b>JobRadar — Daily Digest</b>',
  '<i>Top jobs discovered in the last 24h</i>',
  ''
];

jobs.forEach((job, i) => {
  const medal = medals[i] || `${i + 1}.`;
  const location = esc(job.location || 'N/A');
  const workMode = job.work_mode ? ` (${esc(job.work_mode)})` : '';
  const summary = job.summary ? esc(job.summary).substring(0, 120) + (job.summary.length > 120 ? '\u2026' : '') : '';

  lines.push(`${medal} <b>${esc(job.job_title)}</b>`);
  lines.push(`   \u{1F3E2} ${esc(job.company_name)} | \u{1F4CD} ${location}${workMode}`);
  lines.push(`   \u{2B50} Relevance: <b>${job.relevance_score}/100</b>`);
  if (summary) lines.push(`   \u{1F4AC} <i>${summary}</i>`);
  if (job.source_url) lines.push(`   \u{1F517} <a href="${esc(job.source_url)}">View posting</a>`);
  lines.push('');
});

lines.push(`<i>\u{1F4C5} ${today} | ${jobs.length} job${jobs.length !== 1 ? 's' : ''} matched</i>`);

return [{ json: { text: lines.join('\n') } }];
